import android.util.Base64;
import javax.crypto.Cipher;
import javax.crypto.spec.SecretKeySpec;
import java.security.Key;

public class DataEncryption {

    private static final String ENCRYPTION_KEY = "your_encryption_key";

    public static String encrypt(String plainText) throws Exception {
        Cipher cipher = Cipher.getInstance("AES");
        Key key = new SecretKeySpec(ENCRYPTION_KEY.getBytes(), "AES");

        cipher.init(Cipher.ENCRYPT_MODE, key);
        byte[] encryptedBytes = cipher.doFinal(plainText.getBytes());

        return Base64.encodeToString(encryptedBytes);
    }

    public static String decrypt(String cipherText) throws Exception {
        Cipher cipher = Cipher.getInstance("AES");
        Key key = new SecretKeySpec(ENCRYPTION_KEY.getBytes(), "AES");

        cipher.init(Cipher.DECRYPT_MODE, key);

        byte[] decodedCipherText = Base64.decode(cipherText);
        return new String(cipher.doFinal(decodedCipherText));
    }
}